import { useState } from 'react';
import { Form, Button, ListGroup, Row, Col, Alert } from 'react-bootstrap';

function CardCreator({ cards, onAdd, onClear, onStartReview }) {
  const [question, setQuestion] = useState('');
  const [answer, setAnswer] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!question.trim() || !answer.trim()) return;
    onAdd(question.trim(), answer.trim());
    setQuestion('');
    setAnswer('');
  };

  return (
    <div>
      <Form onSubmit={handleSubmit} className="mb-4">
        <Form.Group className="mb-3">
          <Form.Label>Question</Form.Label>
          <Form.Control
            as="textarea"
            rows={2}
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
            placeholder="Enter question..."
          />
        </Form.Group>
        <Form.Group className="mb-3">
          <Form.Label>Answer</Form.Label>
          <Form.Control
            as="textarea"
            rows={2}
            value={answer}
            onChange={(e) => setAnswer(e.target.value)}
            placeholder="Enter answer..."
          />
        </Form.Group>
        <Button type="submit" variant="primary" disabled={!question.trim() || !answer.trim()}>
          Add Card
        </Button>
      </Form>

      {cards.length > 0 && (
        <>
          <Alert variant="success">
            You have <strong>{cards.length}</strong> card{cards.length !== 1 ? 's' : ''} ready.{' '}
            <Alert.Link onClick={onStartReview} style={{ cursor: 'pointer' }}>
              Start reviewing →
            </Alert.Link>
          </Alert>

          <h5 className="mb-3">Your Cards</h5>
          <ListGroup className="mb-3">
            {cards.map((card, idx) => (
              <ListGroup.Item key={idx}>
                <Row>
                  <Col sm={6}><strong>Q:</strong> {card.question}</Col>
                  <Col sm={6}><strong>A:</strong> {card.answer}</Col>
                </Row>
              </ListGroup.Item>
            ))}
          </ListGroup>
          <Button variant="outline-danger" size="sm" onClick={onClear}>
            Clear All Cards
          </Button>
        </>
      )}
    </div>
  );
}

export default CardCreator;
